Can you refactor this JavaScript pagination function to be cleaner? It feels a bit rough.

```javascript
function paginate(items, page, pageSize) {
  if (!items || items.length == 0) {
    return { data: [], total: 0, pages: 0 };
  }

  const totalPages = Math.ceil(items.length / pageSize);

  // validate page range
  if (page < 1 || page > totalPages) {
    return { data: [], total: items.length, pages: totalPages };
  }

  const start = (page - 1) * pageSize;
  const end = start + pageSize;

  var result = {};
  result.data = items.slice(start, end);  
  result.total = items.length;
  result.pages = totalPages;
  result.currentPage = page;
  result.hasNext = page < totalPages;
  result.hasPrev = page > 1;
  result.nextPage = page < totalPages ? page + 1 : null;
  result.prevPage = page > 0 ? page - 1 : null;

  return result;
}
```

