function validateShippingAddress(addr: { street: string; city: string; zip: string; country: string }) {
  const errors: string[] = [];
  if (!addr.street || addr.street.trim().length === 0) errors.push('Street is required');
  if (!addr.city || addr.city.trim().length === 0) errors.push('City is required');
  if (!addr.zip || !/^\d{5}(-\d{4})?$/.test(addr.zip)) errors.push('Invalid ZIP code');
  if (!addr.country || addr.country.length !== 2) errors.push('Country must be a 2-letter ISO code');
  return errors;
}

function validateBillingAddress(addr: { street: string; city: string; zip: string; country: string; vatNumber?: string }) {
  const errors: string[] = [];
  if (!addr.street || addr.street.trim().length === 0) errors.push('Billing street is required');
  if (!addr.city || addr.city.trim().length === 0) errors.push('Billing city is required');
  if (!addr.zip || !/^\d{5}(-\d{4})?$/.test(addr.zip)) errors.push('Invalid billing ZIP code');
  if (!addr.country || addr.country.length !== 2) errors.push('Billing country must be a 2-letter ISO code');
  if (addr.vatNumber && !/^[A-Z]{2}\d{8,12}$/.test(addr.vatNumber)) errors.push('Invalid VAT number format');
  return errors;
}
